import { assignInlineVars } from '@vanilla-extract/dynamic';

import { Tooltip } from '../../../../../../overlays/tooltip/Tooltip.js';
import { TOOLTIP_HEADER_PADDING } from '../../constants.js';
import {
  seriesActionHeader,
  seriesActionHeaderMultiLine,
  seriesActionHeaderMaxLinesVar,
  TOOLTIP_MAX_WIDTH,
} from '../../tooltip.sty.js';
import type { SeriesName } from '../../types.js';
import { formatSeriesNameForDisplay } from './utils/format-series-name-for-display.js';
import { calculateTotalWidth500 } from '../../utils/width-calculation.js';

export const SeriesActionsHeader = (props: { text: SeriesName }) => {
  const displayText = formatSeriesNameForDisplay(props.text);

  const maxLines = 3;
  const availableWidth = TOOLTIP_MAX_WIDTH - TOOLTIP_HEADER_PADDING * 2;
  const totalTextWidth = calculateTotalWidth500(displayText);

  const isTruncated = Math.ceil(totalTextWidth / availableWidth) > maxLines;

  return (
    <Tooltip text={displayText} disabled={!isTruncated}>
      <div
        className={`${seriesActionHeader} ${seriesActionHeaderMultiLine}`}
        style={assignInlineVars({
          [seriesActionHeaderMaxLinesVar]: String(maxLines),
        })}
      >
        {displayText}
      </div>
    </Tooltip>
  );
};
